#include <iostream>
#include <vector>

// Template class with nested type
template<typename T>
class Container {
public:
 typedef T value_type; // Nested type
 typedef T* pointer;

 void printSize() {
 std::cout << "Size: " << sizeof(T) << std::endl;
 }
};

// Function using typename to access nested type
template<typename T>
void displayTypeInfo() {
 // CORRECT: Using typename to indicate nested type
 typename T::value_type val{};
 typename T::pointer ptr{&val};

 std::cout << "Value type size: " << sizeof(val) << std::endl;
}

int main() {
 Container<int> c;
 c.printSize();
 displayTypeInfo<Container<int>>();
 return 0;
}

#include <iostream>
#include <vector>
#include <list>

// Template template parameter using 'class'
template<typename T, template<typename> class Container>
class Wrapper {
 Container<T> data;
public:
 void add(const T& item) {
 data.push_back(item);
 }
 void display() {
 for(const auto& item : data) {
 std::cout << item << " ";
 }
 std::cout << std::endl;
 }
};

// Modern C++: template template parameter using 'typename'
template<typename T, template<typename> typename Container2>
class ModernWrapper {
 Container2<T> data;
public:
 void add(const T& item) {
 data.push_back(item);
 }
};

int main() {
 // Works with std::vector (but needs allocator parameter)
 // Wrapper<int, std::vector> w1; // Error: vector has 2 params

 // Wrapper with compatible container
 // For demonstration
 std::cout << "Template template parameter demo" << std::endl;
 return 0;
}

#include <iostream>
#include <type_traits>

// Trait to check for nested type
template<typename T, typename = void>
struct HasValueType : std::false_type {};

// Specialization when T::value_type exists
template<typename T>
struct HasValueType<T, typename std::enable_if<
 std::is_same<typename T::value_type, typename T::value_type>::value
>::type> : std::true_type {};

template<typename T>
void processContainer() {
 // typename required here - T::value_type is a dependent type
 typename T::value_type defaultVal{};

 // typename required for function return type
 typename T::value_type createDefault() {
 return typename T::value_type{};
 }

 std::cout << "Default value: " << defaultVal << std::endl;
}

class MyContainer {
public:
 using value_type = int;
};

int main() {
 processContainer<MyContainer>();
 return 0;
}
